// // This LFSR module does not shift the bits on the rising edge of the clock when enable is high.
module lfsr_8bit(
    input clk, 
    input enable, 
    output reg [7:0] lfsr);

    always @(posedge clk) begin
        if (enable)
            lfsr <= {lfsr[6:0], lfsr[7] ^ lfsr[5] ^ lfsr[4] ^ lfsr[3]};
    end
endmodule
